 41→  // ============================================================================
 42→  // Registry (in-memory Map)
 43→  // ============================================================================
 44→
 45→  describe("registry", () => {
 46→    beforeEach(() => {
 47→      clearTemplateDefinitions();
 48→    });
 49→
 50→    test("registerTemplate and getTemplateDefinition", () => {
 51→      registerTemplate({
 52→        eventType: "test.basic",
 53→        header: "Header: {{name}}",
 54→        defaultBody: "Body for {{name}}",
 55→        variables: [{ name: "name", description: "The name" }],
 56→        category: "event",
 57→      });
 58→
 59→      const def = getTemplateDefinition("test.basic");
 60→      expect(def).toBeDefined();
 61→      expect(def!.eventType).toBe("test.basic");
 62→      expect(def!.header).toBe("Header: {{name}}");
 63→      expect(def!.defaultBody).toBe("Body for {{name}}");
 64→    });
 65→
 66→    test("getTemplateDefinition returns undefined for unregistered", () => {
 67→      expect(getTemplateDefinition("no.such.event")).toBeUndefined();
 68→    });
 69→
 70→    test("getAllTemplateDefinitions returns all registered", () => {
 71→      registerTemplate({
 72→        eventType: "test.a",
 73→        header: "",
 74→        defaultBody: "A body",
 75→        variables: [],
 76→        category: "system",
 77→      });
 78→      registerTemplate({
 79→        eventType: "test.b",
 80→        header: "",
 81→        defaultBody: "B body",
 82→        variables: [],
 83→        category: "common",
 84→      });
 85→
 86→      const all = getAllTemplateDefinitions();
 87→      expect(all.length).toBe(2);
