247→    expect(result.unresolved.length).toBe(0);
248→
249→    // Contains role section
250→    expect(result.text).toContain("your role is: worker");
251→    expect(result.text).toContain("worker-agent-001");
252→
253→    // Contains register section
254→    expect(result.text).toContain("join-swarm");
255→
256→    // Contains worker-specific section (not lead)
257→    expect(result.text).toContain("store-progress");
258→    expect(result.text).toContain("task-action");
259→    expect(result.text).not.toContain("CRITICAL DELEGATION RULE");
260→
261→    // Contains filesystem section with interpolated agentId
262→    expect(result.text).toContain("/workspace/shared/thoughts/worker-agent-001/");
263→
264→    // Contains self_awareness
265→    expect(result.text).toContain("How You Are Built");
266→
267→    // Contains context_mode
268→    expect(result.text).toContain("Context Window Management");
269→
270→    // Contains guidelines
271→    expect(result.text).toContain("Operational Guidelines");
272→
273→    // Contains system
274→    expect(result.text).toContain("System packages available");
275→  });
276→
277→  test("composite does NOT include conditional sections (agent_fs, services, artifacts)", () => {
278→    const result = resolveTemplate("system.session.lead", {
279→      role: "lead",
280→      agentId: "test-agent",
281→    });
282→
283→    // agent_fs, services, artifacts are NOT in the composite
284→    expect(result.text).not.toContain("Agent Filesystem (agent-fs)");
285→    expect(result.text).not.toContain("Service Registry");
286→    expect(result.text).not.toContain("localtunnel");
287→  });
288→
289→  test("lead and worker composites differ only in lead vs worker section", () => {
290→    const leadResult = resolveTemplate("system.session.lead", {
291→      role: "lead",
292→      agentId: "test-agent",
293→    });
294→    const workerResult = resolveTemplate("system.session.worker", {
295→      role: "worker",
296→      agentId: "test-agent",
297→    });
298→
299→    // Both share common sections
300→    expect(leadResult.text).toContain("join-swarm");
301→    expect(workerResult.text).toContain("join-swarm");
302→    expect(leadResult.text).toContain("How You Are Built");
303→    expect(workerResult.text).toContain("How You Are Built");
304→
305→    // Lead has lead content, not worker
306→    expect(leadResult.text).toContain("CRITICAL DELEGATION RULE");
307→    expect(leadResult.text).not.toContain("task-action");
308→
309→    // Worker has worker content, not lead
310→    expect(workerResult.text).toContain("task-action");
311→    expect(workerResult.text).not.toContain("CRITICAL DELEGATION RULE");
312→  });
313→});
314→
315→// ============================================================================
316→// Integration with getBasePrompt
317→// ============================================================================
318→
319→describe("Session templates — getBasePrompt integration", () => {
320→  beforeEach(async () => {
321→    await ensureTemplatesRegistered();
322→  });
323→
324→  test("getBasePrompt uses session composite for worker", async () => {
325→    const { getBasePrompt } = await import("../prompts/base-prompt");
