341→    expect(result).toContain("Service Registry");
342→    expect(result).toContain("https://integration-test-worker.swarm.test.com");
343→
344→    // Artifacts included by default
345→    expect(result).toContain("Artifacts");
346→  });
347→
348→  test("getBasePrompt uses session composite for lead", async () => {
349→    const { getBasePrompt } = await import("../prompts/base-prompt");
350→    const result = getBasePrompt({
351→      role: "lead",
352→      agentId: "integration-test-lead",
353→      swarmUrl: "swarm.test.com",
354→    });
355→
356→    // Core sections from composite
357→    expect(result).toContain("your role is: lead");
358→    expect(result).toContain("integration-test-lead");
359→    expect(result).toContain("CRITICAL DELEGATION RULE");
360→
361→    // Should NOT have worker content
362→    expect(result).not.toContain("task-action");
363→  });
